  	"bool":{
      "should":[
        {
          "match":{
          "hobby":"游泳"
          }
        },
        {
          "match":{
          "hobby":"篮球"
          }
        },
        {
          "match":{
          "hobby":"音乐"
          }
        }
      ],
      "minimum_should_match":2
    }
  },
      "highlight":{
        "fields":{
          "hobby":{}
    }
  }
}
```

