        echo "我的年龄是：".$this->age;

    }

}    //类定义结束

//实例化一个对象
$zxn = new Person();

//给 $zxn 对象属性赋值
$zxn->name = "赵喜娜";

$zxn->age = '30';

//调用对象中的 say()方法
$zxn->say();
echo "<br>";
